import React, { useState } from 'react';
import { FaBars, FaTimes } from 'react-icons/fa';

export default function Header() {
  const [menuOpen, setMenuOpen] = useState(false);

  return (
    <header className="main-header" id="home">
      <div className="header-container">
        
        {/* Logo */}
        <h1 className="logo-text">
          <a href="#home">ProjectTime</a>
        </h1>

        {/* Menu Toggle */}
        <button
          className="menu-toggle"
          aria-label="Toggle navigation menu"
          aria-expanded={menuOpen}
          onClick={() => setMenuOpen(!menuOpen)}
        >
          {menuOpen ? <FaTimes size={24} /> : <FaBars size={24} />}
        </button>

        {/* Navigation Links */}
        <nav className={`nav-links ${menuOpen ? 'active' : ''}`}>
          <a href="https://rupankargarai2003.github.io/Projects-Ideas/" className="nav-item" onClick={() => setMenuOpen(false)}>Projects Ideas</a>
          <a href="#services" className="nav-item" onClick={() => setMenuOpen(false)}>Services</a>
          <a href="#about" className="nav-item" onClick={() => setMenuOpen(false)}>About</a>
          <a href="#contact" className="nav-item" onClick={() => setMenuOpen(false)}>Contact</a>
        </nav>

        {/* Contact Info */}
        <div className="contact-info">
          <ul className="contact-list">
            <li className="contact-item">
              <a href="tel:+918391808784">
                <i className="fas fa-phone-alt"></i> (+91) 8391808784
              </a>
            </li>
            <li className="contact-item">
              <a href="mailto:rupankargarai55@gmail.com">
                <i className="fas fa-envelope"></i> rupankargarai55@gmail.com
              </a>
            </li>
          </ul>
        </div>

      </div>
    </header>
  );
}
